class Solution:
    def nextGreaterElements(self, nums: List[int]) -> List[int]:
        n = len(nums)
        ans = [-1] * n
        st = []
        for i in range(2 * n - 1, -1, -1):
            idx = i % n
            while st and nums[st[-1]] <= nums[idx]:
                st.pop()
            if st:
                ans[idx] = nums[st[-1]]
            st.append(idx)
        return ans

